package com.treeeducation.ioas.media.assetfile;
import com.treeeducation.ioas.auth.UserPrincipal;import com.treeeducation.ioas.common.*;import io.swagger.v3.oas.annotations.*;import io.swagger.v3.oas.annotations.tags.Tag;import org.springframework.core.io.InputStreamResource;import org.springframework.data.domain.*;import org.springframework.http.ResponseEntity;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;
/** REST API for package-bound asset files. */
@RestController @RequestMapping("/api/v1/media/assets") @Tag(name="Asset File",description="素材上传、查询、下载、预览、删除与回收站") public class AssetFileController{ private final AssetFileService service; public AssetFileController(AssetFileService service){this.service=service;} @PostMapping("/packages/{packageId}") @Operation(summary="上传文件到主题包") public ApiResponse<AssetFileDtos.Response> upload(@PathVariable Long packageId,@RequestParam AssetFileType type,@RequestParam(required=false) String description,@RequestPart MultipartFile file,@AuthenticationPrincipal UserPrincipal p){return ApiResponse.ok(AssetFileDtos.of(service.upload(packageId,type,description,file,p)));} @GetMapping @Operation(summary="素材文件列表") public ApiResponse<PageResponse<AssetFileDtos.Response>> list(@RequestParam(required=false) Long packageId,@RequestParam(required=false) AssetFileType type,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.ok(PageResponse.of(service.list(packageId,type,PageRequest.of(page,size,Sort.by(Sort.Direction.DESC,"uploadedAt")))));} @DeleteMapping("/{id}") @Operation(summary="删除单文件到回收站") public ApiResponse<Void> delete(@PathVariable Long id,@AuthenticationPrincipal UserPrincipal p){service.softDelete(id,p);return ApiResponse.ok();} @GetMapping("/{id}/download") @Operation(summary="下载素材文件") public ResponseEntity<InputStreamResource> download(@PathVariable Long id){return service.download(id);} @GetMapping("/{id}/preview") @Operation(summary="获取预览地址") public ApiResponse<String> preview(@PathVariable Long id){return ApiResponse.ok(service.get(id).getPreviewUrl());} @GetMapping("/recycle-bin") @Operation(summary="文件回收站列表") public ApiResponse<PageResponse<AssetFileDtos.Response>> recycle(@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.ok(PageResponse.of(service.recycleBin(PageRequest.of(page,size))));} @PostMapping("/recycle-bin/{id}/restore") @Operation(summary="恢复回收站文件") public ApiResponse<AssetFileDtos.Response> restore(@PathVariable Long id,@AuthenticationPrincipal UserPrincipal p){return ApiResponse.ok(AssetFileDtos.of(service.restore(id,p)));} @DeleteMapping("/recycle-bin/{id}/purge") @Operation(summary="永久删除回收站文件") public ApiResponse<Void> purge(@PathVariable Long id,@AuthenticationPrincipal UserPrincipal p){service.purge(id,p);return ApiResponse.ok();}}
